-- ============================================================================
-- 0026_add_invoice_unit_detail.sql
--
-- BACKGROUND
--   The vacant tracker page groups invoices by utility_account_id, but at
--   master-account properties (Onion Creek, EC Tyler, Heritage at Walton
--   Reserve clubhouse) one Sage account number bills many vacant units.
--   The DB has 102 historical invoices on 558's 27104-80000 UA for Feb 2026
--   alone, but they all collapsed into a single tracker row showing the sum.
--
--   per_meter_final.csv has the per-unit detail (description="1-103",
--   meter_id="8010853"), but 0015c-0025 didn't populate any field on the
--   invoice with this info.
--
-- WHAT THIS MIGRATION DOES
--   1. Adds two columns to `invoices`: `unit_label` and `meter_id`. These
--      are general-purpose — useful for any bill with a service-stop or
--      meter identifier (Republic, FPL, etc), not just historical data.
--
--   2. Populates them on historical invoices by matching source_reference to
--      per_meter_final entries. This restores per-unit detail for ~3000 rows
--      across 558 vacant electric, EC Tyler vacant, and similar.
--
-- AFTER RUNNING
--   The vacant page can group by unit_label and show 102 separate rows for
--   558 Feb 2026 instead of one collapsed total.
-- ============================================================================

-- 1) Add columns -----------------------------------------------------------

alter table invoices
  add column if not exists unit_label text,
  add column if not exists meter_id   text;

-- 2) Populate from per_meter_final mapping --------------------------------

do $migration$
declare
  v_pending      int;
  v_updated      int;
  v_unmatched    int;
begin

  create temp table _unit_map (
    source_reference  text primary key,
    unit_label        text,
    meter_id          text
  ) on commit drop;


  select count(*) into v_pending from _unit_map;
  raise notice '[0026] Staged % unit detail mappings.', v_pending;

  update invoices i
     set unit_label = um.unit_label,
         meter_id   = um.meter_id
    from _unit_map um
   where i.source_reference = um.source_reference;

  get diagnostics v_updated = row_count;

  select count(*) into v_unmatched
    from _unit_map um
   where not exists (
     select 1 from invoices i where i.source_reference = um.source_reference
   );

  raise notice '[0026] Updated % invoices with unit detail.', v_updated;
  if v_unmatched > 0 then
    raise notice '[0026] Note: % source_references in mapping had no matching invoice (likely due to renaming or 0017 dedupe).', v_unmatched;
  end if;

end $migration$;

-- 3) Index for vacant page grouping --------------------------------------

create index if not exists invoices_unit_label_idx
  on invoices (utility_account_id, unit_label)
  where unit_label is not null;
